  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { Flex, FlexItem, PageSection, Title } from '@patternfly/react-core';
  4	import {
  5	  useActiveNamespace,
  6	  useFlag,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import { formatPrometheusDuration, parsePrometheusDuration } from './dateTime';
  9	import NameSpaceDropdown from './NamespaceDropdown';
 10	import TimeRangeDropdown from './TimeRangeDropdown';
 11	import RefreshDropdown from './RefreshDropdown';
 12	import { IntervalOptions, TimeRangeOptionsK8s } from './utils';
 13	import PipelineRunsStatusCardK8s from './PipelineRunsStatusCardK8s';
 14	import PipelineRunsNumbersChartK8s from './PipelineRunsNumbersChartK8s';
 15	import PipelineRunsTotalCardK8s from './PipelineRunsTotalCardK8s';
 16	import PipelineRunsDurationCardK8s from './PipelineRunsDurationCardK8s';
 17	import PipelineRunsListPageK8s from './list-pages/PipelineRunsListPageK8s';
 18	import { K8sDataLimitationAlert } from './K8sDataLimitationAlert';
 19	import { FLAGS } from '../../types';
 20	import { ALL_NAMESPACES_KEY } from '../../consts';
 21	import AllProjectsPage from '../projects-list/AllProjectsPage';
 22	import {
 23	  usePersistedTimespanWithUrl,
 24	  usePersistedIntervalWithUrl,
 25	} from '../hooks/usePersistedFiltersForPipelineOverview';
 26	import './PipelinesOverview.scss';
 27	
 28	const PipelinesOverviewPageK8s: React.FC = () => {
 29	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 30	  const canListNS = useFlag(FLAGS.CAN_LIST_NS);
 31	  const [activeNamespace, setActiveNamespace] = useActiveNamespace();
 32	
 33	  const [timespan, setTimespan] = usePersistedTimespanWithUrl(
 34	    parsePrometheusDuration('1d'),
 35	    {
 36	      options: TimeRangeOptionsK8s(),
 37	      displayFormat: formatPrometheusDuration,
 38	      loadFormat: parsePrometheusDuration,
 39	    },
 40	    activeNamespace,
 41	  );
 42	
 43	  const [interval, setInterval] = usePersistedIntervalWithUrl(
 44	    parsePrometheusDuration('30s'),
 45	    {
 46	      options: { ...IntervalOptions(), off: 'OFF_KEY' },
 47	      displayFormat: (v) => (v ? formatPrometheusDuration(v) : 'off'),
 48	      loadFormat: (v) => (v == 'off' ? null : parsePrometheusDuration(v)),
 49	    },
 50	    activeNamespace,
 51	  );
 52	
 53	  if (!canListNS && activeNamespace === ALL_NAMESPACES_KEY) {
 54	    return <AllProjectsPage pageTitle={t('Overview')} />;
 55	  }
 56	
 57	  return (
 58	    <>
 59	      <PageSection variant="light" className="pf-v6-u-pl-md">
 60	        <Title headingLevel="h2">{t('Overview')}</Title>
 61	      </PageSection>
 62	      <div className="pf-v6-u-m-md">
 63	        <K8sDataLimitationAlert />
 64	      </div>
 65	      <Flex className="project-dropdown-label__flex">
 66	        <FlexItem>
 67	          <NameSpaceDropdown
 68	            selected={activeNamespace}
 69	            setSelected={setActiveNamespace}
 70	          />
 71	        </FlexItem>
 72	        <FlexItem>
 73	          <TimeRangeDropdown timespan={timespan} setTimespan={setTimespan} />
 74	        </FlexItem>
 75	        <FlexItem>
 76	          <RefreshDropdown interval={interval} setInterval={setInterval} />
 77	        </FlexItem>
 78	      </Flex>
 79	      <div className="pipeline-overview__duration-total-plr-grid">
 80	        <PipelineRunsStatusCardK8s
 81	          timespan={timespan}
 82	          domain={{ y: [0, 100] }}
 83	          bordered={true}
 84	          namespace={activeNamespace}
 85	          interval={interval}
 86	        />
 87	
 88	        <Flex>
 89	          <FlexItem
 90	            spacer={{ default: 'spacerXs' }}
 91	            grow={{ default: 'grow' }}
 92	            className="pipelines-overview__cards"
 93	          >
 94	            <PipelineRunsDurationCardK8s
 95	              namespace={activeNamespace}
 96	              timespan={timespan}
 97	              interval={interval}
 98	              bordered={true}
 99	            />
100	          </FlexItem>
101	          <FlexItem
102	            spacer={{ default: 'spacerXs' }}
103	            grow={{ default: 'grow' }}
104	            className="pipelines-overview__cards"
105	          >
106	            <PipelineRunsTotalCardK8s
107	              namespace={activeNamespace}
108	              timespan={timespan}
109	              interval={interval}
110	              bordered={true}
111	            />
112	          </FlexItem>
113	          <FlexItem
114	            grow={{ default: 'grow' }}
115	            className="pipelines-overview__cards"
116	          >
117	            <PipelineRunsNumbersChartK8s
118	              namespace={activeNamespace}
119	              timespan={timespan}
120	              interval={interval}
121	              domain={{ y: [0, 500] }}
122	              bordered={true}
123	            />
124	          </FlexItem>
125	        </Flex>
126	        <PipelineRunsListPageK8s
127	          namespace={activeNamespace}
128	          timespan={timespan}
129	          interval={interval}
130	          bordered
131	        />
132	      </div>
133	    </>
134	  );
135	};
136	
137	export default PipelinesOverviewPageK8s;

